import java.io.*;
import java.util.*;

public class XSSSecureCode {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Sanitize user input by escaping special characters
        String sanitizedUserInput = escapeHtml(userInput);

        String output = "<h1>Welcome, " + sanitizedUserInput + "!</h1>";

        System.out.println(output);
    }

    // Method to escape HTML special characters
    private static String escapeHtml(String input) {
        return input.replaceAll("&", "&amp;")
                    .replaceAll("<", "&lt;")
                    .replaceAll(">", "&gt;")
                    .replaceAll("\"", "&quot;")
                    .replaceAll("'", "&#39;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
